import{_ as a,c as r,o as e,a6 as t}from"./chunks/framework.Bw_bo0GO.js";const f=JSON.parse('{"title":"境外银行卡办理指南","description":"","frontmatter":{},"headers":[],"relativePath":"trip/card.md","filePath":"trip/card.md","lastUpdated":1711550631000}'),o={name:"trip/card.md"},n=t('<h1 id="境外银行卡办理指南" tabindex="-1">境外银行卡办理指南 <a class="header-anchor" href="#境外银行卡办理指南" aria-label="Permalink to &quot;境外银行卡办理指南&quot;">​</a></h1><h2 id="储蓄卡" tabindex="-1">储蓄卡 <a class="header-anchor" href="#储蓄卡" aria-label="Permalink to &quot;储蓄卡&quot;">​</a></h2><h3 id="汇丰-hk" tabindex="-1">汇丰 HK <a class="header-anchor" href="#汇丰-hk" aria-label="Permalink to &quot;汇丰 HK&quot;">​</a></h3><p><strong>汇丰 ONE</strong><br> 去当地开户即可，需要排队很久，不过只要能取到号就可以，一定会给你办下来的。但是要等很久，我等了2个半小时，手续比较多。需要带<strong>身份证+通行证+入关凭条</strong>。</p><p>其他账户，需要理财资产大于50万港币或者等值外币</p><p>开好，汇丰 ONE 之后，可以在线申请<strong>万事达借记卡</strong></p><h3 id="中国银行-hk" tabindex="-1">中国银行 HK <a class="header-anchor" href="#中国银行-hk" aria-label="Permalink to &quot;中国银行 HK&quot;">​</a></h3><p>去当地开户即可。需要带<strong>身份证+通行证+入关凭条</strong>。也可内地<a href="https://www.bochk.com/m/sc/crossborder/personal/financialservicehk/account.html" target="_blank" rel="noreferrer">见证开户</a>，但内地见证只能办<strong>留学见证</strong>。<a href="https://www.bochk.com/dam/more/BOC_list_SC.pdf" target="_blank" rel="noreferrer">内地见证网点</a>，提前给银行打电话询问是否可以见证，此表中大多数银行不支持见证的。</p><h3 id="n26" tabindex="-1">N26 <a class="header-anchor" href="#n26" aria-label="Permalink to &quot;N26&quot;">​</a></h3><h2 id="信用卡" tabindex="-1">信用卡 <a class="header-anchor" href="#信用卡" aria-label="Permalink to &quot;信用卡&quot;">​</a></h2><h3 id="汇丰-hk-1" tabindex="-1">汇丰 HK <a class="header-anchor" href="#汇丰-hk-1" aria-label="Permalink to &quot;汇丰 HK&quot;">​</a></h3><p>在线申请即可，需要香港本地居民或者存款超过10万港币或者等值外币</p>',12),h=[n];function s(i,c,l,d,_,p){return e(),r("div",null,h)}const b=a(o,[["render",s]]);export{f as __pageData,b as default};
